from confluent_kafka import Consumer

consumer = Consumer({
    'bootstrap.servers': 'kafka:9092',
    'group.id': 'order-processor',
    'auto.offset.reset': 'earliest'
})
consumer.subscribe(['orders.placed'])

while True:
    msg = consumer.poll(timeout=1.0)
    if msg and not msg.error():
        print(f'offset={msg.offset()} value={msg.value()}')

from airflow.decorators import dag, task
from airflow.sensors.s3_key_sensor import S3KeySensor
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2026, 1, 1), catchup=False)
def daily_pipeline():
    wait_for_file = S3KeySensor(
        task_id='wait_for_vendor_file',
        bucket_name='my-bucket',
        bucket_key='vendor/{{ ds }}/export.parquet'
    )

    @task(retries=3, retry_delay=300)
    def transform(ds=None):
        run_dbt(date=ds)

    wait_for_file >> transform()

daily_pipeline()

