# Delta Live Tables pipeline (Bronze → Silver)
import dlt
from pyspark.sql.functions import col, current_timestamp

@dlt.table(comment='Raw CDC events from Kafka')
def bronze_orders():
    return (
        spark.readStream.format('kafka')
             .option('kafka.bootstrap.servers', 'kafka:9092')
             .option('subscribe', 'orders.cdc')
             .load()
             .withColumn('_ingested_at', current_timestamp())
    )

@dlt.table
@dlt.expect_or_drop('valid_order_id', 'order_id IS NOT NULL')
def silver_orders():
    return dlt.read_stream('bronze_orders') \
               .select('order_id', 'status', 'amount_usd', '_ingested_at')

# Register a schema and check compatibility
import requests

REGISTRY = 'http://schema-registry:8081'

# Register the new version
schema = {
    'type': 'record',
    'name': 'Payment',
    'fields': [
        {'name': 'payment_id', 'type': 'string'},
        {'name': 'amount_cents', 'type': 'long'},
        # New optional field — backward compatible
        {'name': 'currency', 'type': ['null', 'string'],
         'default': None}
    ]
}
resp = requests.post(
    f'{REGISTRY}/subjects/payments-value/versions',
    json={'schema': str(schema)},
    headers={'Content-Type': 'application/vnd.schemaregistry.v1+json'}
)
print(resp.json())  # {'id': 5}
